var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"REPLACER_REPLACER_NULL_NULL","text":{"KOREA":"크르르......","JPN":"クルル……","ENG":"Grrr...","TWN":"吼喔喔……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REPLACER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐, 뭐야! 이것들은?!","JPN":"な、何だ！　こいつら！？","ENG":"W-what the! What are these things?!","TWN":"什麼！這些是？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>후우...... 자네들은 정말 날 짜증나게 하는군.</color>","JPN":"<color=#ffd34c>はあ……君たちは本当に私をイラつかせるな。</color>","ENG":"<color=#ffd34c>Ugh... You lot really have a knack for getting on my nerves.</color>","TWN":"<color=#ffd34c>呼……你們真是會刺激我的神經。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이 목소리는......","JPN":"この声は……","ENG":"That voice...","TWN":"這聲音是……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"사장?","JPN":"社長？","ENG":"Is that the President?","TWN":"老大？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"사장님이라고 해야지. 직원 교육이 엉망이군.","JPN":"社長様と呼べ。教育がなってないな。","ENG":"Mr. President to you. Such terrible manners.","TWN":"應該叫老闆啊，你們的員工培訓全都白費了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"제기랄, 헛소리 말고!","JPN":"クソ、黙ってください！","ENG":"Cut the crap!","TWN":"該死，別瞎扯！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이 괴물들은 뭐야?","JPN":"それより、あの化け物は何ですか！？","ENG":"What's with these monsters?","TWN":"這些怪物是什麼東西啊？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......아니, 괴물이 맞나?","JPN":"いや、これは化け物…というより……","ENG":"Or... are they even monsters?","TWN":"……不對，這些是怪物嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이건...... 마치......","JPN":"まるで……","ENG":"It’s... as if...","TWN":"這是……好像……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그런 거군......","JPN":"そういうことか……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PAWN_REPLACER_HUMAN_BOSS","text":{"KOREA":"호오? 눈치챘나?","JPN":"ほお？　気づいたのか？","ENG":"Oh? So you've caught on?","TWN":"哦？看出來了嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PAWN_REPLACER_HUMAN_BOSS","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"사장...... 아니, 누군진 모르겠지만. 네가 숨기려고 했던 게 이거였군.","JPN":"社長……いや、誰だか知らないが。お前が隠したかったのはこれか。","ENG":"Boss... Or whoever you are... So this is what you've been trying to hide.","TWN":"老闆……不對，雖然不知道是誰，原來他們想隱藏的東西就是這個啊。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"형씨? 이놈들 정체를 아는 거야?","JPN":"お前、こいつらの正体を知ってるのか？","ENG":"Bro? You know what these things are?","TWN":"大哥，你知道他們是什麼嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"짐작은 가는군.","JPN":"予想はつく。","ENG":"I've got a pretty good guess.","TWN":"我能猜到。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이 녀석들...... 아마도 침식된 인간일 거다.","JPN":"こいつらは……多分、侵食体に飲み込まれた人間だ。","ENG":"These things... are probably Corrupted people.","TWN":"這群傢伙……應該是被侵蝕的人。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"훈련 받은 인간을 반쯤 침식시켜서...... 통제 가능한 병사로 사용하는 거지.","JPN":"訓練を受けた人間を半分ほど侵食させて……コントロールが利く兵士として使うんだ。","ENG":"They take people with training and corrupt them half-way through... So they can still serve as soldiers who can take orders.","TWN":"把受過訓練的人侵蝕一半……變成可以控制的士兵。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"아마 우리가 마주쳤던 이상하게 지능적인 침식체들도 비슷한 녀석들이거나...","JPN":"たぶん俺たちと戦った異様に知能の高い侵食体も、これと似たようなやつらか……","ENG":"The unusually intelligent C.O.'s we met were probably something similar...","TWN":"我們遭遇的神奇智慧侵蝕體也是差不多的東西……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};